Code.Terraform:
```hcl
# 为 OpenSearch Dashboards 启用 Amazon Cognito 身份验证
resource "aws_opensearch_domain" "<example_resource_name>" {
  domain_name = "<example_resource_name>"

  cognito_options {
    enabled          = true  # 关键：启用 Dashboards 的 Cognito 身份验证以通过检查
    user_pool_id     = "<USER_POOL_ID>"
    identity_pool_id = "<IDENTITY_POOL_ID>"
    role_arn         = "<ROLE_ARN>"
  }
}
```
